const payload = $input.first().json;

// La API puede devolver productos en diferentes llaves
const productsRaw =
  payload.products ??
  payload.items ??
  payload.data ??
  payload;

// Término de búsqueda (viene del trigger y viaja en el JSON)
const q = String(payload.name ?? '').trim().toUpperCase();

// Normaliza a arreglo
const arr = Array.isArray(productsRaw)
  ? productsRaw
  : Array.isArray(productsRaw?.products)
    ? productsRaw.products
    : [];

// Filtra por nombre si hay término
const filtered = q
  ? arr.filter(p => String(p.name ?? p.displayName ?? '').toUpperCase().includes(q))
  : arr;

// Reduce a top 20 y campos clave
const trimmed = filtered.slice(0, 20).map(p => ({
  id: p._id ?? p.id,
  name: p.name ?? p.displayName ?? '',
  type: (p.type?.name ?? p.type ?? '').toString(),
  code: (p.code ?? p.shortcode ?? '').toString(),
  disabled: !!p.disabled,
}));

return [{ json: { count: trimmed.length, products: trimmed } }];

